mapper.select:
select
row_no,
history_id
from (
select
rownum as row_no,
page_source.history_id
from (
select
/*+ index(h IDX_ISSUE_HISTORY_RECENT_ISSUE) */
h.history_id
from issue_history h
where exists (
select /*+ index(i IDX_ISSUE_PROJECT_ID) */ 1
from issue i
where i.issue_id = h.issue_id
and i.project_id = #{projectId}

)

order by h.changed_at desc, h.history_id desc
) page_source
where rownum <= #{endRow}
)
where row_no >= #{startRow}
order by row_no asc

select /*+ leading(h) use_nl(i u it) */ h.history_id, nvl(h.history_group_id, h.history_id) as history_group_id, h.changed_at, h.changed_by, u.user_name as changed_by_name, h.change_type_code, as change_type_name, as change_type_display_name, h.field_code, as field_name, h.before_value, h.after_value, h.reason, i.issue_id, i.issue_no, '#' || lpad(to_char(i.issue_no), 4, '0') as display_issue_no, i.title as issue_title, i.issue_type_id, it.issue_type_name, i.issue_status_id, i.setting_code_id from ( select h.history_id, h.history_group_id, h.changed_at, h.changed_by, h.change_type_code, h.field_code, h.field_name, h.before_value, h.after_value, h.reason, h.issue_id from issue_history h where h.history_id in
#{historyId}
) h join issue i on h.issue_id = i.issue_id and i.project_id = #{projectId} left join users u on h.changed_by = u.user_id left join issue_type it on i.issue_type_id = it.issue_type_id order by h.changed_at desc, h.history_id desc
